#include "lowpass_filter_10hz.h"
#include <math.h>

/* [REQ-001] [MISRA-Rule-8.9] 静态变量声明 */
static double s_prev = 0.0;  /* 用于存储前一次滤波输出 */
static bool s_fault_detected = false;  /* [REQ-001] [MISRA-Rule-8.9] 故障标志 */

/* [REQ-001] [MISRA-Rule-15.7] 函数参数检查 */
void lowpass_filter_10hz_init(void) {
    /* [REQ-001] [MISRA-Rule-14.3] 初始化静态变量 */
    s_prev = 0.0;
    s_fault_detected = false;
}

/* [REQ-001] [MISRA-Rule-15.7] 输入参数有效性检查 */
double lowpass_filter_10hz_apply(double raw_input) {
    /* [REQ-001] [MISRA-Rule-14.3] 参数有效性检查 */
    if (raw_input < 0.0 || raw_input > 20000.0) {
        /* [REQ-001] [MISRA-Rule-11.3] 故障处理 */
        s_fault_detected = true;
        return 0.0;  /* [REQ-001] [MISRA-Rule-16.4] 返回默认值 */
    }

    /* [REQ-001] [MISRA-Rule-14.3] 静态变量使用 */
    static const double alpha = 1.0 / (1.0 + (2.0 * M_PI * 10.0 / 100.0));  /* [REQ-001] [MISRA-Rule-16.4] 常量定义 */
    double filtered_output = alpha * raw_input + (1.0 - alpha) * s_prev;  /* [REQ-001] [MISRA-Rule-15.7] 算术运算 */

    /* [REQ-001] [MISRA-Rule-16.4] 确保输出非负 */
    if (filtered_output < 0.0) {
        filtered_output = 0.0;
    }

    /* [REQ-001] [MISRA-Rule-14.3] 更新状态变量 */
    s_prev = filtered_output;

    return filtered_output;
}

/* [REQ-001] [MISRA-Rule-15.7] 故障状态查询接口 */
bool lowpass_filter_10hz_get_fault(void) {
    return s_fault_detected;  /* [REQ-001] [MISRA-Rule-14.3] 返回状态变量 */
}

